head.b:skin:
/* 
-----------------------------------------------
Blogger Template Style
Name:        MaxSeo
License:     Premium Version
Version:     2.0
Author:      TemplatesYard
Author Url:  https://www.templatesyard.com/
----------------------------------------------- */

/*
<!-- Variable definitions -->
<Variable name="keycolor" description="Main Color" type="color" default="$(main.color)" value="#3f51b5"/>
<Variable name="followByEmail" description="Follow By Email Text" type="string" default="Get all latest content delivered straight to your inbox." value="Get all latest content delivered straight to your inbox."/>

<Group description="Theme Colors" selector="body">
 <Variable name="main.color" description="Theme Color" type="color" default="#3f51b5" value="#3f51b5"/>
  <Variable name="main.dark.color" description="Dark Color" type="color" default="#202020" value="#202020"/>
  <Variable name="menu.color" description="Menu Color" type="color" default="#ffffff" value="#ffffff"/>
  <Variable name="title.color" description="Title Color" type="color" default="#333333" value="#333333"/>
  <Variable name="title.hover" description="Title Color on Hover" type="color" default="$(main.color)" value="#3f51b5"/>
  <Variable name="footer.color" description="Footer Color" type="color" default="#f1ffff" value="#f1ffff"/>
</Group>

<Group description="Theme Body" selector="body">
  <Variable name="body.background.color" description="Body Background Color" type="color" default="#f8f8f8"  value="#f8f8f8"/>
  <Variable name="body.background" description="Background" type="background" color="$(body.background.color)" default="$(color) url() repeat fixed top left" value="$(color) url() repeat fixed top left"/>
  <Variable name="body.text.color" description="Text Color" type="color" default="#656565"  value="#656565"/>
  <Variable name="body.link.color" description="Link Color" type="color" default="$(main.color)"  value="#3f51b5"/>
</Group>

<!-- Extra Variables -->
<Variable name="body.text.font" description="Font" hideEditor="true" type="font" default="13px Poppins, sans-serif"  value="13px Poppins, sans-serif"/>
<Variable name="posts.background.color" description="Post background color" hideEditor="true" type="color" default="#ffffff"  value="#ffffff"/>
<Variable name="tabs.font" description="Font 2" hideEditor="true" type="font" default="13px Poppins, sans-serif"  value="13px Poppins, sans-serif"/>
<Variable name="posts.title.color" description="Post title color" hideEditor="true" type="color" default="#333333"  value="#333333"/>
<Variable name="posts.text.color" description="Post text color" hideEditor="true" type="color" default="#656565"  value="#656565"/>
<Variable name="posts.icons.color" description="Post icons color" hideEditor="true" type="color" default="$(main.color)"  value="#3f51b5"/>
<Variable name="labels.background.color" description="Label background color" hideEditor="true" type="color" default="$(main.color)"  value="#3f51b5"/>
*/

/*-- Reset CSS --*/
 a,abbr,acronym,address,applet,b,big,blockquote,body,caption,center,cite,code,dd,del,dfn,div,dl,dt,em,fieldset,font,form,h1,h2,h3,h4,h5,h6,html,i,iframe,img,ins,kbd,label,legend,li,object,p,pre,q,s,samp,small,span,strike,strong,sub,sup,table,tbody,td,tfoot,th,thead,tr,tt,u,ul,var{
    padding:0;
    border:0;
    outline:0;
    vertical-align:baseline;
    background:0 0;
    text-decoration:none
}
 .CSS_LIGHTBOX{z-index:999999!important}.CSS_LIGHTBOX_ATTRIBUTION_INDEX_CONTAINER .CSS_HCONT_CHILDREN_HOLDER > .CSS_LAYOUT_COMPONENT.CSS_HCONT_CHILD:first-child > .CSS_LAYOUT_COMPONENT{opacity:0}#google_translate_element { clear: both; }.thread-expanded .thread-count a { display: none; }.comments .continue { display: none!important; }
form,textarea,input,button{
    -webkit-appearance:none;
    -moz-appearance:none;
    appearance:none;
    border-radius:0
}
dl,ul{
    list-style-position:inside;
    font-weight:400;
    list-style:none
}
ul li{
    list-style:none
}
caption,th{
    text-align:center
}
img{
    border:none;
    position:relative
}
a,a:visited{
    text-decoration:none
}
.clearfix{
    clear:both
}
.section,.widget,.widget ul{
    margin:0;
    padding:0
}
a{
    color:$(body.link.color)
}
a img{
    border:0
}
abbr{
    text-decoration:none
}
.CSS_LIGHTBOX{
    z-index:999999!important
}
.separator a{
    clear:none!important;
    float:none!important;
    margin-left:0!important;
    margin-right:0!important
}
#navbar-iframe,.widget-item-control,a.quickedit,.home-link,.feed-links{
    display:none!important
}
.center{
    display:table;
    margin:0 auto;
    position:relative
}
.widget > h2,.widget > h3{
    display:none
}
/*-- Body Content CSS --*/
 body{
    background:$(body.background);
    background-color:$(body.background.color);
    font-family:'Poppins',sans-serif;
    font-size:14px;
    font-weight:400;
    color:$(body.text.color);
    word-wrap:break-word;
    margin:0;
    padding:0
}
 #outer-wrapper{
    margin:0 auto;
    background-color:#f5f6f7;
    box-shadow:0 0 5px rgba(0,0,0,.1)
}
 .row{
    width:1080px
}
 #content-wrapper{
    margin:40px auto 0;
    overflow:hidden
}
 #content-wrapper > .container{
    margin:0 -15px
}
 #main-wrapper{
    float:left;
    overflow:hidden;
    width:66.66666667%;
    box-sizing:border-box;
    word-wrap:break-word;
    padding:0 15px;
    margin:0
}
 #sidebar-wrapper{
    float:right;
    overflow:hidden;
    width:33.33333333%;
    box-sizing:border-box;
    word-wrap:break-word;
    padding:0 15px
}
 .post-image-wrap{
    position:relative;
    display:block
}
 .post-image-link,.about-author .avatar-container,.comments .avatar-image-container{
    background-color:rgba(155,155,155,0.07);
    color:transparent!important
}
 .post-thumb{
    display:block;
    position:relative;
    width:100%;
    height:100%;
    object-fit:cover;
    z-index:1;
   opacity: 0;
    transition: opacity .17s ease;
}
.post-thumb.lazy-yard {
    opacity: 1;
}
 .post-image-link:hover .post-thumb,.post-image-wrap:hover .post-image-link .post-thumb,.hot-item-inner:hover .post-image-link .post-thumb{
    opacity:.9
}
 .post-title a{
    display:block
}
 #top-bar{
    width:100%;
    height:34px;
    background-color:#171c24;
    overflow:hidden;
    margin:0;
    border-bottom:1px solid #12161d
}
 #top-bar .container{
    margin:0 auto
}
 .top-bar-nav{
    position:relative;
    float:left;
    display:block
}
 .top-bar-nav .widget > .widget-title{
    display:none
}
 .top-bar-nav ul li{
    float:left
}
 .top-bar-nav ul li > a{
    height:34px;
    display:block;
    color:#ffffff;
    font-size:12px;
    font-weight:500;
    line-height:34px;
    text-transform:uppercase;
    margin:0 10px 0 0;
    padding:0 5px;
    transition:color .17s
}
 .top-bar-nav ul li:first-child > a{
    padding:0 5px 0 0
}
 .top-bar-nav ul > li:hover > a{
    color:$(main.color)
}
 .top-bar-social{
    position:relative;
    float:right;
    display:block
}
 .top-bar-social .widget > .widget-title{
    display:none
}
 .top-bar-social ul > li{
    float:left;
    display:inline-block
}
 .top-bar-social ul > li > a{
    line-height:34px;
    display:block;
    color:#ffffff;
    text-decoration:none;
    font-size:14px;
    text-align:center;
    padding:0 7px;
    margin:0 0 0 10px;
    transition:color .17s
}
 .top-bar-social ul > li:last-child > a{
    padding:0 0 0 7px
}
 .top-bar-social ul > li:hover > a{
    color:$(main.color)
}
 .social a:before{
    display:inline-block;
    font-family:FontAwesome;
    font-style:normal;
    font-weight:400
}
 .social .blogger a:before{
    content:"\f37d"
}
 .social .facebook a:before{
    content:"\f09a"
}
 .social .twitter a:before{
    content:"\f099"
}
 .social .gplus a:before{
    content:"\f0d5"
}
 .social .rss a:before{
    content:"\f09e"
}
 .social .youtube a:before{
    content:"\f167"
}
 .social .skype a:before{
    content:"\f17e"
}
 .social .stumbleupon a:before{
    content:"\f1a4"
}
 .social .tumblr a:before{
    content:"\f173"
}
 .social .vk a:before{
    content:"\f189"
}
 .social .stack-overflow a:before{
    content:"\f16c"
}
 .social .github a:before{
    content:"\f09b"
}
 .social .linkedin a:before{
    content:"\f0e1"
}
 .social .dribbble a:before{
    content:"\f17d"
}
 .social .soundcloud a:before{
    content:"\f1be"
}
 .social .behance a:before{
    content:"\f1b4"
}
 .social .digg a:before{
    content:"\f1a6"
}
 .social .instagram a:before{
    content:"\f16d"
}
 .social .pinterest a:before{
    content:"\f0d2"
}
 .social .twitch a:before{
    content:"\f1e8"
}
 .social .delicious a:before{
    content:"\f1a5"
}
 .social .codepen a:before{
    content:"\f1cb"
}
 .social .reddit a:before{
    content:"\f1a1"
}
 .social .whatsapp a:before{
    content:"\f232"
}
 .social .snapchat a:before{
    content:"\f2ac"
}
 .social .email a:before{
    content:"\f0e0"
}
 .social .external-link a:before{
    content:"\f35d"
}
 .social-color .blogger a{
    background-color:#ff5722
}
 .social-color .facebook a{
    background-color:#3b5999
}
 .social-color .twitter a{
    background-color:#00acee
}
 .social-color .gplus a{
    background-color:#db4a39
}
 .social-color .youtube a{
    background-color:#f50000
}
 .social-color .instagram a{
    background:linear-gradient(15deg,#ffb13d,#dd277b,#4d5ed4)
}
 .social-color .pinterest a{
    background-color:#ca2127
}
 .social-color .dribbble a{
    background-color:#ea4c89
}
 .social-color .linkedin a{
    background-color:#0077b5
}
 .social-color .tumblr a{
    background-color:#365069
}
 .social-color .twitch a{
    background-color:#6441a5
}
 .social-color .rss a{
    background-color:#ffc200
}
 .social-color .skype a{
    background-color:#00aff0
}
 .social-color .stumbleupon a{
    background-color:#eb4823
}
 .social-color .vk a{
    background-color:#4a76a8
}
 .social-color .stack-overflow a{
    background-color:#f48024
}
 .social-color .github a{
    background-color:#24292e
}
 .social-color .soundcloud a{
    background:linear-gradient(#ff7400,#ff3400)
}
 .social-color .behance a{
    background-color:#191919
}
 .social-color .digg a{
    background-color:#1b1a19
}
 .social-color .delicious a{
    background-color:#0076e8
}
 .social-color .codepen a{
    background-color:#000
}
 .social-color .reddit a{
    background-color:#ff4500
}
 .social-color .whatsapp a{
    background-color:#3fbb50
}
 .social-color .snapchat a{
    background-color:#ffe700
}
 .social-color .email a{
    background-color:#888
}
 .social-color .external-link a{
    background-color:$(main.dark.color)
}
 #header-wrap{
    background-color:#fff;
    position:relative;
    margin:0;
box-shadow:0 2px 4px 0 rgba(0,0,0,.05);
}
 .header-header{
    width:100%;
    height:90px;
    position:relative;
    overflow:hidden;
    padding:25px 0
}
 .header-header .container{
    position:relative;
    margin:0 auto;
    padding:0
}
 .header-logo{
    position:relative;
    float:left;
    width:auto;
    max-width:250px;
    max-height:60px;
    margin:0;
    padding:15px 0
}
 .header-logo .header-image-wrapper{
    display:block
}
 .header-logo img{
    max-width:100%;
    max-height:60px;
    margin:0
}
 .header-logo h1{
    color:$(title.color);
    font-size:20px;
    line-height:1.4em;
    margin:0
}
 .header-logo p{
    font-size:12px;
    margin:5px 0 0
}
 .header-ads{
    position:relative;
    float:right
}
 .header-ads .widget > .widget-title{
    display:none
}
 .header-ads .widget{
    max-width:100%
}
 .header-ads .widget .widget-content{
    width:728px;
    max-width:100%;
    max-height:90px;
    line-height:1
}
 .header-menu{
    position:relative;
    width:100%;
    height:48px;
    z-index:10;
    font-size:13px;
    margin:0;
}
 .header-menu .container{
  background-color: #3f51b5;
    background-image: -webkit-linear-gradient(left,#3f51b5,#03a9f4);
    background-image: linear-gradient(to right,#3f51b5,#03a9f4);
    position:relative;
    margin:0 auto;
    padding:0
}
 #main-menu .widget,#main-menu .widget > .widget-title{
    display:none
}
 #main-menu .show-menu{
    display:block
}
 #main-menu{
    position:relative;
    height:48px;
    z-index:15
}
 #main-menu ul > li{
    float:left;
    position:relative;
    margin:0;
    padding:0;
    transition:background .17s
}
#main-menu ul > li.li-home-icon > a{
    width:48px;
    height:48px;
    text-align:center;
    font-size:18px;
    line-height:48px;
    font-weight:400;
    padding:0
}

 #main-menu ul > li > a{
    position:relative;
    color:$(menu.color);
    font-size:13px;
    font-weight:500;
    text-transform:uppercase;
    line-height:48px;
    display:inline-block;
    margin:0;
    padding:0 13px;
border-right: 1px solid rgba(255,255,255,0.08);
    transition:color .17s ease
}
 #main-menu ul#main-menu-nav > li:first-child > a{

}
 #main-menu ul > li:hover > a{
    color:#fff
}
 #main-menu ul > li > ul{
    position:absolute;
    float:left;
    left:0;
    top:48px;
    width:180px;
    background-color:$(main.dark.color);
    z-index:99999;
    margin:0;
    padding:0;
    box-shadow:0 3px 5px rgba(0,0,0,0.2);
    visibility:hidden;
    opacity:0
}
 #main-menu ul > li > ul > li > ul{
    position:absolute;
    float:left;
    top:0;
    left:100%;
    margin:0
}
 #main-menu ul > li > ul > li{
    display:block;
    float:none;
    position:relative;
    transition:all .17s ease
}
 #main-menu ul > li > ul > li a{
    display:block;
    height:36px;
    font-size:12px;
    color:#fff;
    line-height:36px;
    box-sizing:border-box;
    margin:0;
    padding:0 15px;
    transition:all .17s ease
}
 #main-menu ul > li > ul > li:hover{
    background-color:rgba(0,0,0,0.2)
}
 #main-menu ul > li > ul > li:hover > a{
    color:$(main.color)
}
 #main-menu ul > li.has-sub > a:after{
    content:'\f107';
    float:right;
    font-family:FontAwesome;
    font-size:14px;
    font-weight:400;
    margin:0 0 0 3px
}
 #main-menu ul > li > ul > li.has-sub > a:after{
    content:'\f105';
    float:right;
    margin:0
}
 #main-menu .mega-menu{
    position:static!important
}
 #main-menu .mega-menu > ul{
    width:100%;
    box-sizing:border-box;
    padding:20px 10px
}
 #main-menu .mega-menu > ul.mega-menu-inner{
    overflow:hidden
}
 #main-menu ul > li:hover > ul,#main-menu ul > li > ul > li:hover > ul{
    visibility:visible;
    opacity:1
}
 #main-menu ul ul{
    transition:all .17s ease
}
 .mega-menu-inner .mega-item{
    float:left;
    width:25%;
    box-sizing:border-box;
    padding:0 10px
}
 .mega-menu-inner .mega-content{
    position:relative;
    width:100%;
    overflow:hidden;
    padding:0
}
 .mega-content .post-image-wrap{
    width:100%;
    height:140px;
    overflow:hidden
}
 .mega-content .post-image-link{
    width:100%;
    height:100%;
    z-index:1;
    display:block;
    position:relative;
    overflow:hidden
}
 .mega-content .post-title{
    position:relative;
    font-size:14px;
    font-weight:500;
    line-height:1.5em;
    margin:7px 0 5px
}
 .mega-content .post-title a{
    display:block;
    color:#fff;
    transition:color .17s
}
 .mega-content:hover .post-title a{
    color:$(title.hover)
}
 .mega-content .post-meta{
    color:#aaa
}
 .no-posts{
    float:left;
    width:100%;
    height:100px;
    line-height:100px;
    text-align:center
}
 .mega-menu .no-posts{
    line-height:60px;
    color:$(title.color)
}
 .show-search,.hide-search{
    position:absolute;
    right:0;
    top:0;
    display:block;
    width:48px;
    height:48px;
    line-height:48px;
    z-index:20;
    color:$(menu.color);
    font-size:15px;
    text-align:center;
    cursor:pointer;
    transition:color .17s ease
}
 .show-search:before{
    content:"\f002";
    font-family:FontAwesome;
    font-weight:400
}
 .hide-search:before{
    content:"\f00d";
    font-family:FontAwesome;
    font-weight:400
}
 .show-search:hover,.hide-search:hover{
    color:#fff
}
 #nav-search{
    display:none;
    position:absolute;
    left:0;
    top:0;
    width:100%;
    height:48px;
    z-index:99;
    background-color:$(main.color);
    box-sizing:border-box;
    padding:0
}
 #nav-search .search-form{
    width:100%;
    height:48px;
    background-color:rgba(0,0,0,0);
    line-height:48px;
    overflow:hidden;
    padding:0
}
 #nav-search .search-input{
    width:100%;
    height:48px;
    font-family:inherit;
    color:$(menu.color);
    margin:0;
    padding:0 46px 0 15px;
    background-color:rgba(0,0,0,0);
    font-size:14px;
    font-weight:400;
    box-sizing:border-box;
    border:0
}
 #nav-search .search-input:focus{
    color:$(menu.color);
    outline:none
}
 .slide-menu-toggle{
    display:none;
    position:absolute;
    line-height:48px;
    height:48px;
    width:48px;
    top:0;
    left:0;
    font-family:FontAwesome;
    color:#fff;
    font-size:17px;
    font-weight:400;
    text-align:left;
    cursor:pointer;
    z-index:4;
    padding:0
}
 .slide-menu-toggle:before{
    content:"\f0c9"
}
 .nav-active .slide-menu-toggle:before{
    content:"\f00d"
}
 .mobile-menu{
    display:none;
    position:absolute;
    top:48px;
    left:0;
    width:100%;
    background-color:$(main.dark.color);
    box-sizing:border-box;
    padding:20px;
    border-top:1px solid rgba(255,255,255,0.08);
    visibility:hidden;
    opacity:0;
    transform-origin:0 0;
    transform:scaleY(0);
    transition:all .17s ease
}
 .nav-active .mobile-menu{
    visibility:visible;
    opacity:1;
    transform:scaleY(1)
}
 .mobile-menu > ul{
    margin:0
}
 .mobile-menu .m-sub{
    display:none;
    padding:0
}
 .mobile-menu ul li{
    position:relative;
    display:block;
    overflow:hidden;
    float:left;
    width:100%;
    font-size:13px;
    font-weight:500;
    text-transform:uppercase;
    line-height:38px;
    margin:0;
    padding:0
}
 .mobile-menu > ul li ul{
    overflow:hidden
}
 .mobile-menu ul li a{
    color:#fff;
    padding:0;
    display:block;
    transition:all .17s ease
}
 .mobile-menu ul li.has-sub .submenu-toggle{
    position:absolute;
    top:0;
    right:0;
    color:#fff;
    cursor:pointer
}
 .mobile-menu ul li.has-sub .submenu-toggle:after{
    content:'\f105';
    font-family:FontAwesome;
    font-weight:400;
    float:right;
    width:34px;
    font-size:16px;
    text-align:center;
    transition:all .17s ease
}
 .mobile-menu ul li.has-sub.show > .submenu-toggle:after{
    transform:rotate(90deg)
}
 .mobile-menu > ul > li > ul > li > a{
    color:#fff;
    opacity:.7;
    padding:0 0 0 15px
}
 .mobile-menu > ul > li > ul > li > ul > li > a{
    color:#fff;
    opacity:.7;
    padding:0 0 0 30px
}
 .mobile-menu ul li a:hover,.mobile-menu ul > li > .submenu-toggle:hover{
    color:$(main.color)
}
 .post-meta{
    overflow:hidden;
    color:#aaaaaa;
    font-size:11px;
    font-weight:500;
    text-transform:uppercase;
    padding:0 1px
}
 .post-meta .post-author,.post-meta .post-date{
    float:left;
    display:inline-block;
    margin:0 10px 0 0
}
 .post-meta .post-author:before,.post-meta .post-date:before{
    font-family:FontAwesome;
    font-weight:400;
    margin:0 3px 0 0
}
 .post-meta .post-author:before{
    content:'\f007'
}
 .post-meta .post-date:before{
    content:'\f017'
}
 .post-meta a{
    color:#aaaaaa;
    transition:color .17s
}
 .post-meta a:hover{
    color:$(main.color)
}
 #hot-wrapper{
    margin:0 auto
}
 #hot-section .widget,#hot-section .widget > .widget-title{
    display:none
}
 #hot-section .show-hot{
    display:block!important
}

 #hot-section .show-hot .widget-content{
    position:relative;
    overflow:hidden;
    height:410px;
    margin:20px 0 0;
background-color: #ffffff;
padding: 20px;
    border-radius: 4px;
    box-shadow: 0 2px 4px rgba(0,0,0,.05);
}
 .hot-loader{
    position:relative;
    height:100%;
    overflow:hidden;
    display:block
}
 .hot-loader:after{
    content:'';
    position:absolute;
    top:50%;
    left:50%;
    width:26px;
    height:26px;
    margin:-15px 0 0 -15px;
    border:2px solid #ddd;
    border-left-color:$(main.color);
    border-top-color:$(main.color);
    border-radius:100%;
    animation:spinner .8s infinite linear;
    transform-origin:center
}
 @-webkit-keyframes spinner {
     0%{
        -webkit-transform:rotate(0deg);
        transform:rotate(0deg)
    }
     to{
        -webkit-transform:rotate(1turn);
        transform:rotate(1turn)
    }
}
 @keyframes spinner {
     0%{
        -webkit-transform:rotate(0deg);
        transform:rotate(0deg)
    }
     to{
        -webkit-transform:rotate(1turn);
        transform:rotate(1turn)
    }
}
 ul.hot-posts{
    position:relative;
    overflow:hidden;
    height:410px;
    margin:0 -5px
}
 .hot-posts .hot-item{
    position:relative;
    float:left;
    width:25%;
    height:200px;
    overflow:hidden;
    box-sizing:border-box;
    padding:0 5px
}
 .hot-posts .hot-item.item-0{
    width:50%;
    height:410px
}

.hot-posts .hot-item.item-1 {
    width: 50%;
    margin:0 0 10px
}
 .hot-item-inner{
    position:relative;
    float:left;
    width:100%;
    height:100%;
    overflow:hidden;
    display:block;
border-radius: 4px;
}
 .hot-posts .post-image-link{
    width:100%;
    height:100%;
    position:relative;
    overflow:hidden;
    display:block;
border-radius: 4px;
}
 .hot-posts .post-info{
    position:absolute;
    bottom:0;
    left:0;
    width:100%;
    background-image:linear-gradient(rgba(0,0,0,0),#000);
    overflow:hidden;
    z-index:5;
    box-sizing:border-box;
    padding:20px
}
 .hot-posts .post-title{
    font-size:14px;
    font-weight:500;
    display:block;
    line-height:1.5em;
    margin:10px 0 5px
}
 .hot-posts .item-0 .post-title{
    font-size:21px;
    margin:10px 0
}
 .hot-posts .item-1 .post-title{
 font-size:18px;
}
 .hot-posts .post-title a{
    color:#fff;
    display:block
}
 .hot-posts .post-meta,.hot-posts .post-meta a{
    color:#fff
}
 .show-hot .no-posts{
    position:absolute;
    top:calc(50% - 50px);
    left:0;
    width:100%
}
 .queryMessage{
    overflow:hidden;
    background-color:#f2f2f2;
    color:$(title.color);
    font-size:13px;
    font-weight:400;
    padding:8px 10px;
    margin:0 0 25px
}
 .queryMessage .query-info{
    margin:0 5px
}
 .queryMessage .search-query,.queryMessage .search-label{
    font-weight:700;
    text-transform:uppercase
}
 .queryMessage .search-query:before,.queryMessage .search-label:before{
    content:"\201c"
}
 .queryMessage .search-query:after,.queryMessage .search-label:after{
    content:"\201d"
}
 .queryMessage a.show-more{
    float:right;
    color:$(title.hover);
    text-decoration:underline;
    transition:opacity .17s
}
 .queryMessage a.show-more:hover{
    opacity:.8
}
 .queryEmpty{
    font-size:13px;
    font-weight:400;
    padding:10px 0;
    margin:0 0 25px;
    text-align:center
}
 .title-wrap{
