 .back-top{
    display:none;
    z-index:1010;
    width:32px;
    height:32px;
    position:fixed;
    bottom:25px;
    right:25px;
    cursor:pointer;
    overflow:hidden;
    font-size:13px;
    color:#fff;
    text-align:center;
    line-height:32px
}
 .back-top:before{
    content:'';
    position:absolute;
    top:0;
    left:0;
    right:0;
    bottom:0;
    background-color:$(main.color);
    opacity:.5;
    transition:opacity .17s ease
}
 .back-top:after{
    content:'\f077';
    position:relative;
    font-family:FontAwesome;
    font-weight:400;
    opacity:.8;
    transition:opacity .17s ease
}
 .back-top:hover:before,.back-top:hover:after,.nav-active .back-top:after,.nav-active .back-top:before{
