}
 @media screen and (max-width: 880px) {
     .footer-widgets-wrap{
        display:block
    }
     #footer-wrapper .footer{
        width:100%;
        margin-right:0
    }
     #footer-sec2,#footer-sec3{
        margin-top:25px
    }
}
@media screen and (max-width: 767px) {
.hot-posts .hot-item.item-0 {
    width: 100%;
       height: 280px;
margin-bottom:10px;
}
#hot-section .show-hot .widget-content, #hot-section .hot-posts {
    height: auto;
}
}
 @media screen and (max-width: 680px) {
     #hot-section .show-hot .widget-content,#hot-section .hot-posts{
        height:auto
    }
     #hot-section .hot-loader{
        height:200px
    }
     .hot-posts .hot-item{
        width:100%;
        height:220px;
        margin:10px 0 0
    }
     .hot-posts .hot-item.item-0, .hot-posts .hot-item.item-1{
        width:100%;
        height:250px;
        margin:0
    }
     .hot-posts .hot-item.item-1,.hot-posts .hot-item.item-2{
        margin:10px 0 0
    }
     .hot-posts .post-title{
        font-size:18px
    }
     .index-post{
        width:100%
    }
}
 @media screen and (max-width: 560px) {
     .top-bar-nav{
        display:none
    }
     .top-bar-social{
        width:100%;
        text-align:center
    }
     .top-bar-social ul > li{
        float:none
    }
     .top-bar-social ul > li > a{
        margin:0 5px
    }
     .top-bar-social ul > li:last-child > a{
        padding:0 5px
    }
     .hot-posts .hot-item{
        height:200px
    }
     .index-post .post-image-wrap{
        margin:0 0 15px
    }
     ul.related-posts{
        margin:0
    }
     .related-posts .related-item{
        width:100%;
        padding:0;
        margin:20px 0 0
    }
     .related-posts .item-0{
        margin:0
    }
     .related-posts .post-tag{
        display:none
    }
     .related-posts .post-image-link{
        width:80px;
        height:70px;
        float:left;
        margin:0 12px 0 0
    }
     .related-posts .post-title{
        font-size:13px;
        overflow:hidden;
        margin:0 0 5px
    }
     .post-reactions{
        display:none
    }
}
 @media screen and (max-width: 440px) {
     .hot-posts .hot-item.item-0, .hot-posts .hot-item.item-1{
        height:200px
    }
     .hot-posts .item-0 .post-title{
        font-size:19px
    }
     .queryMessage{
        text-align:center
    }
     .queryMessage a.show-more{
        width:100%;
        margin:10px 0 0
    }
     .item-post h1.post-title{
        font-size:24px
    }
     .about-author{
        text-align:center
    }
     .about-author .avatar-container{
        float:none;
        display:table;
        margin:0 auto 10px
    }
     #comments ol{
        padding:0
    }
     .errorWrap{
        padding:70px 0 100px
    }
     .errorWrap h3{
        font-size:120px
    }
}
 @media screen and (max-width: 360px) {
     .about-author .avatar-container{
        width:60px;
        height:60px
    }
}

b:if.b:template-skin:
/*------Layout (No Edit)----------*/
body#layout #outer-wrapper,body#layout .row{
    width:auto;
    padding:0
}
 body#layout{
    width:800px;
    position:relative;
    padding:95px 5px 0;
    margin:0
}
 body#layout div.section{
    margin:0 5px 10px!important;
    padding:16px 16px 18px!important
}
 body#layout .section h4{
    font-size:14px;
    margin:0
}
 body#layout .layout-widget-description{
    display:none
}
 body#layout .theme-options,body#layout #main-menu .widget{
    display:block!important
}
 body#layout div.sora-panel{
    background-color:#d7d7d7!important;
    overflow:hidden!important;
    border-color:#bcbcbc
}
 body#layout .sora-panel .widget{
    float:left;
    width:49%;
    margin-right:2%
}
 body#layout .sora-panel #LinkList71{
    margin-right:0
}
 body#layout #top-bar{
    height:auto
}
 body#layout #top-bar .container{
    display:flex
}
 body#layout .top-bar-nav,body#layout .top-bar-social{
    width:50%
}
 body#layout #header-wrap{
    height:auto
}
 body#layout .header-header{
    float:left;
    width:100%;
    height:auto;
    padding:0
}
 body#layout .header-header .container{
    display:flex
}
 body#layout div.header-logo,body#layout div.header-ads{
    float:left;
    width:50%;
    height:auto;
    max-width:none;
    max-height:none
}
 body#layout .header-ads .widget-content{
    width:auto
}
 body#layout .header-ads .add_widget{
    padding:15px!important
}
 body#layout .mobile-header{
    display:block;
    float:right;
    width:33.33%;
    height:auto
}
 body#layout .mobile-menu{
    display:none
}
 body#layout .header-menu{
    float:left;
    width:100%;
    height:auto
}
 body#layout #main-menu{
    height:auto
}
 body#layout #hot-wrapper .widget{
    display:block
}
 body#layout #content-wrapper{
    margin:0
}
 body#layout #content-wrapper > .container{
    display:flex;
    margin:0
}
 body#layout #main-wrapper{
    width:66.66%;
    padding:0
}
 body#layout #sidebar-wrapper{
    width:33.33%;
    padding:0
}
 body#layout .sidebar .widget,body#layout .sidebar .widget-content{
    float:none;
    overflow:visible
}
 body#layout .footer-widgets-wrap{
    display:flex
}
 body#layout .footer-widgets-wrap div.footer{
    width:100%
}

/*------Layout (end)----------*/

